// ── Legacy mock helpers (kept for any remaining mock services) ────────────────
import { ApiResponse, PaginatedResponse } from "@/types";

export async function apiSuccess<T>(data: T, message?: string): Promise<ApiResponse<T>> {
  return { data, success: true, message };
}

export async function apiError<T>(error: string): Promise<ApiResponse<T>> {
  return { data: null as T, success: false, error };
}

export async function paginatedSuccess<T>(
  data: T[], page: number, limit: number, total: number
): Promise<PaginatedResponse<T>> {
  return { data, success: true, page, limit, total, totalPages: Math.ceil(total / limit) };
}
